+import type { ConfigurableTrait, Trait, TraitRecord } from '../trait/types';
+import type { World } from '../world/types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; pair: RelationPair };
+
+export type Deferred = {
+    spawn(...traits: ConfigurableTrait[]): Entity;
+    destroy(entity: Entity): void;
+    add(entity: Entity, ...traits: ConfigurableTrait[]): void;
+    remove(entity: Entity, ...traits: (Trait | RelationPair)[]): void;
+    addExclusive(entity: Entity, pair: RelationPair): void;
+    flush(): void;
+};
+
+function commandsFor(world: World): Command[] {
+    const ctx = world[$internal];
+    return ctx.deferredBuffers[ctx.deferredBuffers.length - 1];
+}
+
+export function hasPendingCommands(world: World, entity?: Entity): boolean {
+    return world[$internal].deferredBuffers.some((buffer) =>
+        buffer.some((command) => entity === undefined || command.entity === entity)
+    );
+}
+
+export function flushDeferred(world: World): void {
+    const ctx = world[$internal];
+    const buffer = commandsFor(world);
+    if (!buffer.length) return;
+
+    // A nested flush owns its own command list; commands queued by callbacks wait
+    // for that scope rather than being appended to the list we are iterating.
+    ctx.deferredBuffers.push([]);
+    try {
+        for (const command of buffer.splice(0)) {
+            if (command.type === 'spawn') {
+                // Spawn + destroy in the same buffer is intentionally a no-op.
+                if (isDestroyedInBuffer(command.entity, buffer)) continue;
+                activateEntityReservation(world, command.entity, ...command.traits);
+                continue;
+            }
+
+            // Commands against entities which have already died are harmless.
+            if (!world.has(command.entity)) continue;
+            if (command.entity === ctx.worldEntity && command.type === 'destroy') {
+                throw new Error('Koota: The world entity cannot be destroyed through deferred commands.');
+            }
+
+            switch (command.type) {
+                case 'destroy':
+                    destroyEntity(world, command.entity);
+                    break;
+                case 'add':
+                    addTrait(world, command.entity, ...command.traits);
+                    break;
+                case 'remove':
+                    removeTrait(world, command.entity, ...command.traits);
+                    break;
+                case 'exclusive': {
+                    const pairCtx = command.pair[$internal];
+                    const relation = pairCtx.relation;
+                    removeTrait(world, command.entity, relation('*'));
+                    if (pairCtx.target !== '*') addTrait(world, command.entity, command.pair);
+                    break;
+                }
+            }
+        }
+    } finally {
+        ctx.deferredBuffers.pop();
+    }
+}
+
+function isDestroyedInBuffer(entity: Entity, commands: Command[]): boolean {
+    return commands.some((command) => command.type === 'destroy' && command.entity === entity);
+}
+
+export function createDeferred(world: World): Deferred {
+    return {
+        spawn(...traits) {
+            const entity = reserveEntity(world[$internal].entityIndex);
+            commandsFor(world).push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            commandsFor(world).push({ type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            commandsFor(world).push({ type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            commandsFor(world).push({ type: 'remove', entity, traits });
+        },
+        addExclusive(entity, pair) {
+            commandsFor(world).push({ type: 'exclusive', entity, pair });
+        },
+        flush() {
+            flushDeferred(world);
+        },
+    };
+}
+
+/** Virtual membership used by entity.has while a buffer is pending. */
+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    if (!hasPendingCommands(world, entity)) return undefined;
+    let result = isRelationPair(trait)
+        ? entity.has(trait)
+        : hasTrait(world, entity, trait);
+
+    for (const buffer of world[$internal].deferredBuffers) {
+        for (const command of buffer) {
+            if (command.entity !== entity) continue;
+            if (command.type === 'destroy') return false;
+            if (command.type === 'spawn') result = false;
+            if (command.type === 'add') {
+                for (const config of command.traits) {
+                    if (isRelationPair(config)) {
+                        if (isRelationPair(trait) && samePair(config, trait)) result = true;
+                    } else if (!isRelationPair(trait) && traitOf(config) === trait) result = true;
+                }
+            }
+            if (command.type === 'remove') {
+                for (const remove of command.traits) {
+                    if (isRelationPair(remove)) {
+                        if (isRelationPair(trait) && (samePair(remove, trait) || remove[$internal].target === '*')) result = false;
+                    } else if (!isRelationPair(trait) && remove === trait) result = false;
+                }
+            }
+            if (command.type === 'exclusive' && isRelationPair(trait)) {
+                const a = command.pair[$internal];
+                const b = trait[$internal];
+                if (a.relation === b.relation) result = a.target !== '*' && a.target === b.target;
+            }
+        }
+    }
+    return result;
+}
+
+export function deferredGet<T extends Trait | RelationPair>(
+    world: World,
+    entity: Entity,
+    trait: T
+): TraitRecord<any> | undefined {
+    if (!hasPendingCommands(world, entity)) return undefined;
+    let value = getTrait(world, entity, trait);
+    for (const buffer of world[$internal].deferredBuffers) {
+        for (const command of buffer) {
+            if (command.entity !== entity) continue;
+            if (command.type === 'destroy') return undefined;
+            if (command.type === 'add') {
+                for (const config of command.traits) {
+                    if (isRelationPair(config) && isRelationPair(trait) && samePair(config, trait)) value = config[$internal].params as any;
+                    else if (!isRelationPair(config) && !isRelationPair(trait) && traitOf(config) === trait) value = Array.isArray(config) ? config[1] as any : value;
+                }
+            }
+        }
+    }
+    return deferredHas(world, entity, trait) ? value : undefined;
+}
+
+function traitOf(config: ConfigurableTrait): Trait {
+    return (Array.isArray(config) ? config[0] : config) as Trait;
+}
+
+function samePair(a: RelationPair, b: RelationPair): boolean {
+    return a[$internal].relation === b[$internal].relation && a[$internal].target === b[$internal].target;
